ALGORITHM SimpleModuloHash
INPUT: message string, prime p
OUTPUT: hash value (integer)

BEGIN
  // Step 1: Convert message to numeric blocks
  blocks[] = SplitIntoBlocks(message, blockSize)

  // Step 2: Initialize hash value
  H = 0  // Initial Value (IV)

  // Step 3: Iterative processing of each block
  FOR EACH block M_i IN blocks DO
    // Apply compression function: H_i = (H_{i-1} + M_i) mod p
    H = (H + M_i) MOD p
  END FOR

  // Step 4: Return final hash digest
  RETURN H
END

