ALGORITHM DaviesMeyerHash
INPUT: message string, blockCipher E
OUTPUT: hash value (binary string)

BEGIN
  // Step 1: Split message into key-sized blocks
  blocks[] = SplitIntoBlocks(message, keySize)

  // Step 2: Initialize hash value (Initial Value)
  H = "0000...0"  // zeros matching block size

  // Step 3: Iterative compression
  FOR i = 1 TO blocks.length DO
    M_i = blocks[i]  // Current message block as key

    // Encrypt current hash using message block as key
    C = E Encrypt(Key: M_i, Plaintext: H)

    // Apply feedforward: H_i = E(M_i, H_{i-1}) XOR H_{i-1}
    H = C XOR H
  END FOR

  // Step 4: Return final hash digest
  RETURN H
END

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

/*
 * Simple Modulo Hash Function Implementation
 * Formula: H_i = (H_{i-1} + M_i) mod p
 * 
 * This is a cryptographically weak hash function for educational purposes.
 */

#define MAX_BLOCKS 100

/* Structure to hold hash computation state */
typedef struct {
    int hash_value;
    int prime;
    int block_count;
    int intermediate[ MAX_BLOCKS ];
} HashState;

/*
 * Compute Simple Modulo Hash
 * Returns the final hash digest
 */
int simple_modulo_hash(const char* message, int prime) {
    int hash_value = 0;  // Initial Value (IV) = 0
    int block_value;

    printf("\n========================================\n");
    printf("SIMPLE MODULO HASH (p = %d)\n", prime);
    printf("========================================\n");
    printf("Message: \"%s\"\n\n", message);

    // Process each character as a block
    for (int i = 0; message[i] != '\0'; i++) {
        block_value = (int)message[i];  // Get ASCII value

        printf("Block %d: M_%d = %d ('%c')\n", 
               i+1, i+1, block_value, message[i]);

        // Apply compression: H_i = (H_{i-1} + M_i) mod p
        int old_hash = hash_value;
        hash_value = (hash_value + block_value) % prime;

        printf("  H_%d = (%d + %d) mod %d = %d\n", 
               i, old_hash, block_value, prime, hash_value);
    }

    printf("\n--------------------------------------\n");
    printf("Final Hash Digest: %d\n", hash_value);
    printf("--------------------------------------\n");

    return hash_value;
}

/*
 * Demonstrate collision vulnerability
 */
void demonstrate_collision(int prime) {
    char* messages[] = {"university", "ABC", "123", "!?A", "aAb", "@#$"};
    int num_messages = 6;
    int hash_values[6];

    printf("\n========================================\n");
    printf("COLLISION DEMONSTRATION (p = %d)\n", prime);
    printf("========================================\n");

    for (int i = 0; i < num_messages; i++) {
        hash_values[i] = simple_modulo_hash(messages[i], prime);
    }

    // Find collisions
    printf("\n--- Hash Values Summary ---\n");
    for (int i = 0; i < num_messages; i++) {
        printf("\"%s\" -> %d\n", messages[i], hash_values[i]);
    }

    // Simple collision check
    printf("\n*** Note: This demonstrates weak collision resistance ***\n");
}

/*
 * Simple demonstration of Davies-Meyer concept
 * Uses a mock "cipher" for educational purposes
 */
void davies_meyer_demo(const char* message) {
    printf("\n========================================\n");
    printf("DAVIES-MEYER HASH CONCEPT DEMO\n");
    printf("========================================\n");
    printf("Formula: H_i = E(M_i, H_{i-1}) XOR H_{i-1}\n\n");

    // Simplified 4-bit demonstration
    int H = 0b0000;  // Initial Value

    printf("Initial H0 = %04b\n\n", H);

    for (int i = 0; message[i] != '\0' && i < 3; i++) {
        int M = message[i] & 0x0F;  // Use lower 4 bits as "key"

        // Mock "encryption": rotate bits based on key (educational only)
        // In real implementation, this would be AES or similar
        int E_result = ((M << 2) | (M >> 2)) & 0x0F;  // 4-bit rotation

        int old_H = H;
        H = E_result ^ old_H;  // Feedforward: XOR with previous hash

        printf("Block %d: M=%04b (key), E(M,H)=%04b, H_%d=%04b XOR %04b = %04b (%d)\n",
               i+1, M, E_result, i, old_H, E_result, H, H);
    }

    printf("\nFinal Hash Digest: %04b (%d)\n", H, H);
    printf("Note: Real implementation uses AES/DES as block cipher\n");
}

